prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_456ee830_bc3c_4f84_8cf1_387f05f0eb06> .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER NOT EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-A1631E07-215E-4AFA-B398-51ECDA3271B5>
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
